# --- Secure Storage ---
# Authorization codes: code -> {user_id, client_id, redirect_uri, created_at, used, code_challenge, scope}
auth_codes = {}

# Issued tokens: token -> {user_id, client_id, scope, created_at, expires_at}
access_tokens = {}

# Refresh tokens: token -> {user_id, client_id, scope, created_at}
refresh_tokens = {}

# Registered clients: client_id -> {client_secret_hash, redirect_uris, name}
registered_clients = {}

