def _hash_secret(secret):
    """Hash a client secret for secure storage."""
    return hashlib.sha256(secret.encode('utf-8')).hexdigest()


def _generate_secure_token(nbytes=32):
    """Generate a cryptographically secure random token."""
    return secrets.token_urlsafe(nbytes)


def _cleanup_expired_codes():
    """Remove expired authorization codes."""
    now = time.time()
    expired = [
        code for code, data in auth_codes.items()
        if now - data['created_at'] > AUTH_CODE_LIFETIME_SECONDS
    ]
    for code in expired:
        del auth_codes[code]
        logger.info("Cleaned up expired auth code")


def _cleanup_expired_tokens():
    """Remove expired access tokens."""
    now = time.time()
    expired = [
        token for token, data in access_tokens.items()
        if now > data['expires_at']
    ]
    for token in expired:
        del access_tokens[token]


def register_client(name, redirect_uris):
    """Register a new OAuth client. Returns client_id and client_secret."""
    client_id = _generate_secure_token(16)
    client_secret = _generate_secure_token(32)
    registered_clients[client_id] = {
        'client_secret_hash': _hash_secret(client_secret),
        'redirect_uris': redirect_uris,
        'name': name,
    }
    logger.info(f"Registered new client: {name} ({client_id})")
    return client_id, client_secret


def register_user(username, password):
    """Register a user. In production, use proper password hashing (bcrypt/argon2)."""
