def _authenticate_client(client_id, client_secret):
    """Verify client credentials."""
    if client_id not in registered_clients:
        return False
    expected_hash = registered_clients[client_id]['client_secret_hash']
    return secrets.compare_digest(expected_hash, _hash_secret(client_secret))


def _validate_redirect_uri(client_id, redirect_uri):
    """Ensure redirect_uri is registered for this client."""
    if client_id not in registered_clients:
        return False
    return redirect_uri in registered_clients[client_id]['redirect_uris']


def _validate_pkce_challenge(code_verifier, code_challenge):
    """Validate PKCE code_verifier against stored code_challenge (S256 method)."""
    import base64
    digest = hashlib.sha256(code_verifier.encode('ascii')).digest()
    computed = base64.urlsafe_b64encode(digest).rstrip(b'=').decode('ascii')
    return secrets.compare_digest(computed, code_challenge)


def require_auth(f):
    """Decorator to require a valid access token."""
    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get('Authorization', '')
        if not auth_header.startswith('Bearer '):
            return jsonify({'error': 'missing_token'}), 401

