@app.route('/authorize', methods=['GET'])
def authorize():
    """
    Authorization endpoint. In production, this would render a login/consent page.
    Required params: response_type, client_id, redirect_uri, state
    Recommended: code_challenge, code_challenge_method (PKCE)
    """
    response_type = request.args.get('response_type')
    client_id = request.args.get('client_id')
    redirect_uri = request.args.get('redirect_uri')
    state = request.args.get('state')
    scope = request.args.get('scope', '')
    code_challenge = request.args.get('code_challenge')
    code_challenge_method = request.args.get('code_challenge_method')

    # Validate required parameters
    if response_type != 'code':
        return jsonify({'error': 'unsupported_response_type'}), 400

    if not client_id or client_id not in registered_clients:
        return jsonify({'error': 'invalid_client'}), 400

    if not redirect_uri or not _validate_redirect_uri(client_id, redirect_uri):
        # Per RFC 6749 §4.1.2.1: Do NOT redirect if redirect_uri is invalid
        return jsonify({'error': 'invalid_redirect_uri'}), 400

    if not state:
        # State is required to prevent CSRF
        return jsonify({'error': 'missing_state', 'description': 'state parameter is required'}), 400

    if code_challenge_method and code_challenge_method != 'S256':
        return jsonify({'error': 'invalid_request', 'description': 'Only S256 code_challenge_method is supported'}), 400

    # In production: authenticate the user via login form and get consent
    # For this demo, we simulate an authenticated user
    # You would check session for logged-in user
    user_id = request.args.get('user_id')  # Simulated; in production, use session
    if not user_id or user_id not in users:
        return jsonify({
            'error': 'login_required',
            'description': 'User must authenticate. Pass user_id for demo purposes.'
        }), 401

    # Cleanup expired codes
    _cleanup_expired_codes()

    # Generate authorization code
    code = _generate_secure_token(32)
    auth_codes[code] = {
        'user_id': user_id,
        'client_id': client_id,
        'redirect_uri': redirect_uri,
        'scope': scope,
        'created_at': time.time(),
        'used': False,  # Track single-use
        'code_challenge': code_challenge,  # PKCE
    }

    logger.info(f"Issued auth code for user {user_id}, client {client_id}")

    # Redirect back to client with code and state
    separator = '&' if '?' in redirect_uri else '?'
    redirect_url = f"{redirect_uri}{separator}code={code}&state={state}"
    return redirect(redirect_url)


@app.route('/token', methods=['POST'])
def token():
    """
    Token endpoint. Exchanges authorization code for access token.
    Codes are single-use per RFC 6749 §4.1.2.
    Also supports refresh_token grant.
    """
    grant_type = request.form.get('grant_type')

    if grant_type == 'authorization_code':
        return _handle_authorization_code_grant()
    elif grant_type == 'refresh_token':
        return _handle_refresh_token_grant()
    else:
        return jsonify({'error': 'unsupported_grant_type'}), 400


def _handle_authorization_code_grant():
    """Handle authorization_code grant type."""
    code = request.form.get('code')
    client_id = request.form.get('client_id')
    client_secret = request.form.get('client_secret')
    redirect_uri = request.form.get('redirect_uri')
    code_verifier = request.form.get('code_verifier')  # PKCE

    # Authenticate the client
    if not client_id or not client_secret:
        return jsonify({'error': 'invalid_client', 'description': 'Client credentials required'}), 401

    if not _authenticate_client(client_id, client_secret):
        logger.warning(f"Failed client authentication for client_id: {client_id}")
        return jsonify({'error': 'invalid_client'}), 401

    # Validate the authorization code
    if not code or code not in auth_codes:
        logger.warning("Invalid or missing authorization code")
        return jsonify({'error': 'invalid_grant', 'description': 'Invalid authorization code'}), 400

    code_data = auth_codes[code]

    # Check if code has expired
    if time.time() - code_data['created_at'] > AUTH_CODE_LIFETIME_SECONDS:
        del auth_codes[code]
        logger.warning("Expired authorization code used")
        return jsonify({'error': 'invalid_grant', 'description': 'Authorization code has expired'}), 400

    # SECURITY: Authorization codes MUST be single-use (RFC 6749 §4.1.2)
    if code_data['used']:
        # If a code is used twice, it indicates a potential attack.
        # Per RFC 6749: revoke all tokens issued based on this code.
        logger.warning(f"SECURITY: Auth code reuse detected for user {code_data['user_id']}! "
                       f"Revoking associated tokens.")
        _revoke_tokens_for_user_and_client(code_data['user_id'], code_data['client_id'])
        del auth_codes[code]
        return jsonify({
            'error': 'invalid_grant',
            'description': 'Authorization code has already been used. '
                           'All associated tokens have been revoked for security.'
        }), 400

    # Verify the code was issued to this client
    if code_data['client_id'] != client_id:
        logger.warning(f"Client mismatch: code issued to {code_data['client_id']}, "
                       f"presented by {client_id}")
        return jsonify({'error': 'invalid_grant', 'description': 'Code was not issued to this client'}), 400

    # Verify redirect_uri matches
    if code_data['redirect_uri'] != redirect_uri:
        return jsonify({'error': 'invalid_grant', 'description': 'redirect_uri mismatch'}), 400

    # Verify PKCE if code_challenge was provided during authorization
    if code_data['code_challenge']:
        if not code_verifier:
            return jsonify({'error': 'invalid_grant', 'description': 'code_verifier required'}), 400
        if not _validate_pkce_challenge(code_verifier, code_data['code_challenge']):
            logger.warning("PKCE verification failed")
            return jsonify({'error': 'invalid_grant', 'description': 'PKCE verification failed'}), 400

    # Mark code as used (single-use enforcement)
    code_data['used'] = True

    # Generate tokens
    access_token = _generate_secure_token(32)
    refresh_token = _generate_secure_token(32)
    now = time.time()

    access_tokens[access_token] = {
        'user_id': code_data['user_id'],
        'client_id': client_id,
        'scope': code_data['scope'],
        'created_at': now,
        'expires_at': now + ACCESS_TOKEN_LIFETIME_SECONDS,
    }

    refresh_tokens[refresh_token] = {
        'user_id': code_data['user_id'],
        'client_id': client_id,
        'scope': code_data['scope'],
        'created_at': now,
    }

    logger.info(f"Issued access token for user {code_data['user_id']}, client {client_id}")

    return jsonify({
        'access_token': access_token,
        'token_type': 'Bearer',
        'expires_in': ACCESS_TOKEN_LIFETIME_SECONDS,
        'refresh_token': refresh_token,
        'scope': code_data['scope'],
    })


def _handle_refresh_token_grant():
    """
    Handle refresh_token grant type.
    This provides retry resilience — if a token exchange fails at the network level,
    the client can use the refresh token to get a new access token.
    """
    refresh_token_value = request.form.get('refresh_token')
    client_id = request.form.get('client_id')
    client_secret = request.form.get('client_secret')

    if not client_id or not client_secret:
        return jsonify({'error': 'invalid_client'}), 401

    if not _authenticate_client(client_id, client_secret):
        return jsonify({'error': 'invalid_client'}), 401

    if not refresh_token_value or refresh_token_value not in refresh_tokens:
        return jsonify({'error': 'invalid_grant', 'description': 'Invalid refresh token'}), 400

    rt_data = refresh_tokens[refresh_token_value]

    if rt_data['client_id'] != client_id:
        return jsonify({'error': 'invalid_grant'}), 400

    # Rotate refresh token (invalidate old one, issue new one)
    del refresh_tokens[refresh_token_value]

    now = time.time()
    new_access_token = _generate_secure_token(32)
    new_refresh_token = _generate_secure_token(32)

    access_tokens[new_access_token] = {
        'user_id': rt_data['user_id'],
        'client_id': client_id,
        'scope': rt_data['scope'],
        'created_at': now,
        'expires_at': now + ACCESS_TOKEN_LIFETIME_SECONDS,
    }

    refresh_tokens[new_refresh_token] = {
        'user_id': rt_data['user_id'],
        'client_id': client_id,
        'scope': rt_data['scope'],
        'created_at': now,
    }

    logger.info(f"Refreshed token for user {rt_data['user_id']}, client {client_id}")

    return jsonify({
        'access_token': new_access_token,
        'token_type': 'Bearer',
        'expires_in': ACCESS_TOKEN_LIFETIME_SECONDS,
        'refresh_token': new_refresh_token,
        'scope': rt_data['scope'],
    })


def _revoke_tokens_for_user_and_client(user_id, client_id):
    """Revoke all tokens for a user/client pair (used when code reuse is detected)."""
    tokens_to_revoke = [
        t for t, data in access_tokens.items()
        if data['user_id'] == user_id and data['client_id'] == client_id
    ]
    for t in tokens_to_revoke:
        del access_tokens[t]

    rts_to_revoke = [
        t for t, data in refresh_tokens.items()
        if data['user_id'] == user_id and data['client_id'] == client_id
    ]
    for t in rts_to_revoke:
        del refresh_tokens[t]

    logger.info(f"Revoked {len(tokens_to_revoke)} access tokens and "
                f"{len(rts_to_revoke)} refresh tokens for user {user_id}, client {client_id}")


@app.route('/revoke', methods=['POST'])
def revoke():
    """Token revocation endpoint (RFC 7009)."""
    token_value = request.form.get('token')
    token_type_hint = request.form.get('token_type_hint', 'access_token')
    client_id = request.form.get('client_id')
    client_secret = request.form.get('client_secret')

    if not _authenticate_client(client_id, client_secret):
        return jsonify({'error': 'invalid_client'}), 401

    if token_type_hint == 'refresh_token' and token_value in refresh_tokens:
        if refresh_tokens[token_value]['client_id'] == client_id:
            del refresh_tokens[token_value]
    elif token_value in access_tokens:
        if access_tokens[token_value]['client_id'] == client_id:
            del access_tokens[token_value]

    # Per RFC 7009: always return 200 even if token wasn't found
    return jsonify({}), 200


@app.route('/userinfo', methods=['GET'])
@require_auth
def userinfo():
    """Protected resource endpoint — returns user info for valid token."""
    token_data = request.token_data
    user_id = token_data['user_id']

    if user_id not in users:
        return jsonify({'error': 'user_not_found'}), 404

    return jsonify({
        'user_id': user_id,
        'username': users[user_id]['username'],
        'scope': token_data['scope'],
    })


@app.route('/introspect', methods=['POST'])
def introspect():
    """Token introspection endpoint (RFC 7662)."""
    client_id = request.form.get('client_id')
    client_secret = request.form.get('client_secret')

    if not _authenticate_client(client_id, client_secret):
        return jsonify({'error': 'invalid_client'}), 401

    token_value = request.form.get('token')

    if token_value in access_tokens:
        data = access_tokens[token_value]
        active = time.time() < data['expires_at']
        return jsonify({
            'active': active,
            'client_id': data['client_id'],
            'user_id': data['user_id'],
            'scope': data['scope'],
            'exp': int(data['expires_at']),
        })

    return jsonify({'active': False})


